# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import Flask, request, redirect, url_for, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'

def is_authenticated():
    return session.get('authenticated', False)

@app.route('/login', methods=['GET', 'POST'])
def login():
    next_url = request.args.get('next') or url_for('default_page')
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        # Replace the following check with your actual authentication logic
        if username == 'admin' and password == 'admin':
            session['authenticated'] = True
            return redirect(next_url)
        return 'Invalid credentials', 401
    return '''
    <form method="post">
        <input type="text" name="username" placeholder="Username" required />
        <input type="password" name="password" placeholder="Password" required />
        <input type="submit" value="Login" />
    </form>
    '''

@app.route('/')
def default_page():
    return 'This is the default homepage.'

@app.route('/protected')
def protected():
    if not is_authenticated():
        return redirect(url_for('login', next=request.url))
    return 'This is a protected page. You are logged in.'

if __name__ == '__main__':
    app.run(debug=True)